package com.ayush.mockito; import org.junit.jupiter.api.Test; import org.mockito.InOrder; import static org.junit.jupiter.api.Assertions.*; import static org.mockito.Mockito.*; class MyServiceTest { @Test void mockingAndStubbing(){ ExternalApi api=mock(ExternalApi.class); when(api.getData()).thenReturn("Mock Data"); assertEquals("Mock Data", new MyService(api).fetchData()); } @Test void verifyingInteractions(){ ExternalApi api=mock(ExternalApi.class); new MyService(api).fetchData(); verify(api).getData(); } @Test void argumentMatching(){ ExternalApi api=mock(ExternalApi.class); new MyService(api).publish("hello"); verify(api).sendData(eq("hello")); } @Test void handlingVoidMethods(){ ExternalApi api=mock(ExternalApi.class); doNothing().when(api).clear(); new MyService(api).clearData(); verify(api).clear(); } @Test void multipleReturns(){ ExternalApi api=mock(ExternalApi.class); when(api.getData()).thenReturn("First").thenReturn("Second"); assertEquals("First | Second", new MyService(api).fetchTwice()); } @Test void interactionOrder(){ ExternalApi api=mock(ExternalApi.class); MyService s=new MyService(api); s.fetchData(); s.publish("done"); InOrder order=inOrder(api); order.verify(api).getData(); order.verify(api).sendData("done"); } @Test void voidMethodThrowsException(){ ExternalApi api=mock(ExternalApi.class); doThrow(new RuntimeException("clear failed")).when(api).clear(); assertThrows(RuntimeException.class, () -> new MyService(api).clearData()); }}